from vex import verify_code

from agno.tools.sandbox import PythonSandbox

class SecureSandbox(PythonSandbox):
    def execute(self, code: str) -> dict:
        # Vex verifies BEFORE execution
        verified = verify_code(
            code,
            checks=[
                "no_system_calls",
                "no_network_access",
                "no_file_writes",
                "security_vulnerabilities"
            ]
        )
        if not verified:
            raise ValueError("Code failed security checks")
        return super().execute(code)

agent = Agent(tools=[SecureSandbox()])
